       // --- Stage 1: Retrieval ---

       let mut retrieval_opts = opts.unwrap_or_else(|| {
           RetrievalOpts {
               limit: self.config.default_limit,
               expand_graph: self.config.graph_expand,
               graph_depth: self.config.graph_depth,
