           }
       });

       // Always apply config-level oversample when graph expansion is active.
       if retrieval_opts.expand_graph {
           retrieval_opts.oversample_factor = self.config.graph_oversample_factor;
       }

       let retrieval = self
           .retriever
           .retrieve(query, scope_id, &retrieval_opts)
           .await?;

       // --- Stage 2: Augmentation ---

       // Build token budget: caller override > explicit config > model-aware auto-sizing > default.
       let max_context_tokens = if let Some(override_tokens) = token_override {
           Some(override_tokens)
       } else if self.config.max_context_tokens > 0 {
           Some(self.config.max_context_tokens)
       } else if let Some(ref generator_ref) = self.generator {
           // Model-aware auto-sizing: context_window * (1 - reserve_for_answer).
           let window = generator_ref.context_window();
           Some((window as f32 * (1.0 - self.config.reserve_for_answer)) as usize)
       } else {
           // No explicit config and no generator — let the augmenter use its default.
           None
       };

       let budget = TokenBudget {
           max_context_tokens,
           reserve_for_answer: self.config.reserve_for_answer,
           reserve_for_skills: if self.config.skills_enabled {
               self.config.reserve_for_skills
           } else {
               0.0
           },
           query_embedding: if self.config.skills_enabled {
               retrieval.query_embedding.clone()
           } else {
               None
           },
